parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Clinical Trial Data",
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "output": {
        "type": "object",
        "properties": {
          "distinct_actions": {
            "type": "array",
            "items": {
              "type": "string",
              "minLength": 1
            },
            "uniqueItems": true,
            "minItems": 1,
            "description": "Array of unique clinical trial actions, procedures, and assessments"
          },
          "total_count": {
            "type": "integer",
            "minimum": 0,
            "description": "Total count of distinct actions"
          }
        },
        "required": ["distinct_actions", "total_count"],
        "additionalProperties": false
      }
    },
    "required": ["output"],
    "additionalProperties": false
  }
}

parameters.jsCode:
const phases = $('Schedule of Activities').first().json.output.phases;
const hasMultipleArms = phases.some(phase =>
  phase.schedule_of_activities.some(visit => visit.treatment_arm !== "ALL")
);

return [
  {
    json: {
      output: {
        data: {
          phases: phases,
          metadata: {
            start_page: $('Map Pages').first().json['Start Page'],
            end_page: $('Map Pages').first().json['End Page'],
            researchid: $('Webhook').first().json.body.researchId,
            siteid: $('Webhook').first().json.body.siteId,
            activities: $('Reorder activities').first().json.output[0].output.distinct_actions,
            total_phases: phases.length,
            has_multiple_arms: hasMultipleArms
          }
        }
      }
    }
  }
];

// Extract distinct actions_to_perform from phases[].schedule_of_activities[]

const phases = $input.first().json?.output?.phases ?? [];

// Collect all actions from all phases and all meetings
const allActions = phases.flatMap((phase) =>
  (phase?.schedule_of_activities ?? []).flatMap((meeting) => {
    const actions = meeting?.actions_to_perform;
    if (Array.isArray(actions)) return actions;
    if (typeof actions === "string" && actions.trim()) return [actions.trim()];
    return [];
  })
);

// Deduplicate + sort
const distinctActions = [...new Set(allActions)]
  .filter((x) => typeof x === "string" && x.trim())
  .map((x) => x.trim())
  .sort((a, b) => a.localeCompare(b));

// Return single item with output object
return [
  {
    json: {
      output: {
        distinct_actions: distinctActions,
        total_count: distinctActions.length,
      },
    },
  },
];

